def describe(name, *details, **props):
    mc.postToChat(f"{name}: {len(details)} деталей")
    for key, val in props.items():
        mc.postToChat(f"{key} = {val}")

describe("Башня", "основа", "крыша", высота=10, цвет="серый")

def build_wall(x, y, z, w, h):
    """Строит стену шириной w и высотой h из камня."""
    for i in range(w):
        for j in range(h):
            mc.setBlock(x + i, y + j, z, block.STONE.id)

help(build_wall)

class InvalidSize(Exception):
    pass

def build_cube(size):
    if size <= 0 or size > 50:
        raise InvalidSize(f"Плохой размер: {size}")
    mc.postToChat(f"Строю куб {size}")

try:
    build_cube(int(input("Размер: ")))
except InvalidSize as e:
    mc.postToChat(str(e))

import csv

def build_maze(filename, x, y, z):
    with open(filename) as f:
        for row_i, row in enumerate(csv.reader(f)):
            for col_i, cell in enumerate(row):
                if int(cell) == 1:
                    for h in range(3):
                        mc.setBlock(x+col_i, y+h, z+row_i, block.STONE.id)

pos = mc.player.getTilePos()
build_maze("maze.csv", pos.x, pos.y, pos.z)

def build_farm(x, y, z, w, L):
    for i in range(-1, w + 1):
        mc.setBlock(x+i, y, z-1, 85)
        mc.setBlock(x+i, y, z+L, 85)
    crops = [59, 141, 142]
    for i in range(w):
        for j in range(L):
            if i % 4 == 0:
                mc.setBlock(x+i, y-1, z+j, block.WATER.id)
            else:
                mc.setBlock(x+i, y-1, z+j, 60)
                mc.setBlock(x+i, y, z+j, crops[i % 3])

pos = mc.player.getTilePos()
build_farm(pos.x, pos.y, pos.z, 12, 8)

from buildings import build_castle

def main():
    """Точка входа: строит замок выбранного размера."""
    size = input("Размер (S/M/L): ").upper()
    sizes = {"S": 10, "M": 20, "L": 30}
    pos = mc.player.getTilePos()
    if size in sizes:
        build_castle(pos.x, pos.y, pos.z, sizes[size])
    else:
        mc.postToChat("Неизвестный размер")

main()
